                    + "one,two,\"th,ree\"\n"
                    + "\"a\\\\\"\n"
                    + "a\\,b\n"
                    + "\"a\\\\,b\"";
    final String[][] res = {
        {"one", "two", "three"},
        {"on\\\"e", "two"},
        {"on\"e", "two"},
        {"one", "tw\"o"},
        {"one", "t\\,wo"}, // backslash in quotes only
        {"one", "two", "th,ree"},
        {"a\\\\"}, // backslash in quotes only escapes a delimiter (",")
        {"a\\", "b"}, // a backslash must be returned
